package com.projectbible.shop.maven.jpa.mysql.category.presentation;
import com.projectbible.shop.maven.jpa.mysql.category.application.CategoryQueryService; import com.projectbible.shop.maven.jpa.mysql.common.api.ApiResponse; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import java.util.List; import java.util.Map; import org.springframework.web.bind.annotation.*;
@Tag(name="categories") @RestController @RequestMapping("/api/v1/categories") public class CategoryController { private final CategoryQueryService service; public CategoryController(CategoryQueryService service) { this.service=service; } @Operation(summary="List categories") @GetMapping public ApiResponse<List<Map<String,Object>>> list() { List<Map<String,Object>> items=service.list(); return ApiResponse.success(items,Map.of("page",1,"limit",items.size(),"totalCount",items.size(),"totalPages",1)); } }
